  1	import * as React from 'react';
  2	import { FDF_FLAG } from '@odf/core/redux';
  3	import { useGetExternalClusterDetails } from '@odf/core/redux/utils';
  4	import {
  5	  DEFAULT_INFRASTRUCTURE,
  6	  InfrastructureKind,
  7	  InfrastructureModel,
  8	  RHCS_SUPPORTED_INFRA,
  9	  useCustomTranslation,
 10	  useK8sGet,
 11	} from '@odf/shared';
 12	import { useWatchStorageClusters } from '@odf/shared/hooks/useWatchStorageClusters';
 13	import { getInfrastructurePlatform } from '@odf/shared/utils';
 14	import { useFlag } from '@openshift-console/dynamic-plugin-sdk';
 15	import { ModalComponent } from '@openshift-console/dynamic-plugin-sdk/lib/app/modal-support/ModalProvider';
 16	import { useNavigate } from 'react-router-dom-v5-compat';
 17	import {
 18	  Flex,
 19	  FlexItem,
 20	  Card,
 21	  CardHeader,
 22	  CardTitle,
 23	  CardBody,
 24	  TextContent,
 25	  Text,
 26	  Modal,
 27	  Title,
 28	  Button,
 29	  Radio,
 30	  ButtonVariant,
 31	} from '@patternfly/react-core';
 32	
 33	type ConfigureDFSelectionsProps = {
 34	  selectedOption: ExternalSystemOption;
 35	  setSelectedOption: (option: ExternalSystemOption) => void;
 36	};
 37	
 38	enum ExternalSystemOption {
 39	  RedHatCeph = 'redhat-ceph',
 40	  IBMFlash = 'ibm-flash',
 41	  Scale = 'scale',
 42	  SAN = 'san',
 43	}
 44	
 45	const ConfigureExternalSystems: React.FC<ConfigureDFSelectionsProps> = ({
 46	  selectedOption,
 47	  setSelectedOption,
 48	}) => {
 49	  const { t } = useCustomTranslation();
 50	
 51	  const isFDF = useFlag(FDF_FLAG);
 52	  const [infrastructure] = useK8sGet<InfrastructureKind>(
 53	    InfrastructureModel,
 54	    DEFAULT_INFRASTRUCTURE
 55	  );
 56	
 57	  const externalClusterDetails = useGetExternalClusterDetails();
 58	  const hasExternalStorageClusters = externalClusterDetails.clusterName !== '';
 59	  const platform = getInfrastructurePlatform(infrastructure);
 60	  const isRHCSSupported = RHCS_SUPPORTED_INFRA.includes(platform);
 61	
 62	  // Check if Scale cluster or SAN cluster exists
 63	  const { remoteClusters, sanClusters } = useWatchStorageClusters();
 64	  const hasScaleCluster =
 65	    remoteClusters?.loaded &&
 66	    !remoteClusters?.loadError &&
 67	    remoteClusters?.data?.length > 0;
 68	  const hasSANCluster =
 69	    sanClusters?.loaded &&
 70	    !sanClusters?.loadError &&
 71	    sanClusters?.data?.length > 0;
 72	  // SAN tile should be disabled if either Scale or SAN cluster exists
 73	  const shouldDisableSAN = hasScaleCluster || hasSANCluster;
 74	  return (
 75	    <Flex
 76	      direction={{ default: 'column' }}
 77	      spaceItems={{ default: 'spaceItemsXl', md: 'spaceItemsMd' }}
 78	      className="pf-v6-u-mt-md"
 79	    >
 80	      <FlexItem>
 81	        <Card
 82	          id="setup-ceph-cluster"
 83	          isClickable={isRHCSSupported && !hasExternalStorageClusters}
 84	          isDisabled={!isRHCSSupported || hasExternalStorageClusters}
 85	        >
 86	          <CardHeader
 87	            selectableActions={{
 88	              onClickAction: () =>
 89	                setSelectedOption(ExternalSystemOption.RedHatCeph),
 90	              selectableActionId: 'ceph-cluster',
 91	            }}
 92	          >
 93	            <CardTitle>{t('Red Hat/IBM Ceph Cluster')}</CardTitle>
 94	          </CardHeader>
 95	          <CardBody>
 96	            <Flex direction={{ default: 'row' }}>
 97	              <FlexItem>
 98	                <TextContent>
 99	                  <Text component="small">
100	                    {t(
101	                      'Provision a storage cluster using local devices on your OpenShift nodes.'
102	                    )}
103	                  </Text>
104	                </TextContent>
105	              </FlexItem>
106	              <FlexItem align={{ default: 'alignRight' }}>
107	                <Radio
108	                  isDisabled={!isRHCSSupported || hasExternalStorageClusters}
109	                  isChecked={selectedOption === ExternalSystemOption.RedHatCeph}
110	                  onChange={() =>
111	                    setSelectedOption(ExternalSystemOption.RedHatCeph)
112	                  }
113	                  name="setup-ceph-radio"
114	                  id="setup-ceph-radio"
115	                />
116	              </FlexItem>
117	            </Flex>
118	          </CardBody>
119	        </Card>
120	      </FlexItem>
121	      <FlexItem>
122	        <Card isClickable id="connect-flash-system">
123	          <CardHeader
124	            selectableActions={{
125	              onClickAction: () =>
126	                setSelectedOption(ExternalSystemOption.IBMFlash),
127	              selectableActionId: 'flash-system',
128	            }}
129	          >
130	            <CardTitle>{t('IBM FlashSystem')}</CardTitle>
131	          </CardHeader>
132	          <CardBody>
133	            <Flex direction={{ default: 'row' }}>
134	              <FlexItem>
135	                <TextContent>
136	                  <Text component="small">
137	                    {t(
138	                      'Connect to an IBM FlashSystem to power Data Foundation with fast reliable block storage optimized for enterprise performance.'
139	                    )}
140	                  </Text>
141	                </TextContent>
142	              </FlexItem>
143	              <FlexItem align={{ default: 'alignRight' }}>
144	                <Radio
145	                  isChecked={selectedOption === ExternalSystemOption.IBMFlash}
146	                  onChange={() =>
147	                    setSelectedOption(ExternalSystemOption.IBMFlash)
148	                  }
149	                  name="setup-flash-radio"
150	                  id="setup-flash-radio"
151	                />
152	              </FlexItem>
153	            </Flex>
154	          </CardBody>
155	        </Card>
156	      </FlexItem>
157	      {isFDF && (
158	        <>
159	          <FlexItem>
160	            <Card id="setup-scale-storage" isClickable>
161	              <CardHeader
162	                selectableActions={{
163	                  selectableActionId: 'scale-storage',
164	                  onClickAction: () =>
165	                    setSelectedOption(ExternalSystemOption.Scale),
166	                }}
167	              >
168	                <CardTitle>{t('IBM Scale')}</CardTitle>
169	              </CardHeader>
170	              <CardBody>
171	                <Flex direction={{ default: 'row' }}>
172	                  <FlexItem>
173	                    <TextContent>
174	                      <Text component="small">
175	                        {t(
176	                          'Connect to IBM Storage Scale to deliver fast, scalable file storage for Data Foundation'
177	                        )}
178	                      </Text>
179	                    </TextContent>
180	                  </FlexItem>
181	                  <FlexItem align={{ default: 'alignRight' }}>
182	                    <Radio
183	                      isChecked={selectedOption === ExternalSystemOption.Scale}
184	                      onChange={() =>
185	                        setSelectedOption(ExternalSystemOption.Scale)
186	                      }
187	                      name="setup-scale-radio"
188	                      id="setup-scale-radio"
189	                    />
190	                  </FlexItem>
191	                </Flex>
192	              </CardBody>
193	            </Card>
194	          </FlexItem>
195	          <FlexItem>
196	            <Card
197	              id="setup-san-storage"
198	              isClickable={!shouldDisableSAN}
199	              isDisabled={shouldDisableSAN}
200	            >
201	              <CardHeader
202	                selectableActions={{
203	                  selectableActionId: 'san-storage',
204	                  onClickAction: () =>
205	                    setSelectedOption(ExternalSystemOption.SAN),
206	                }}
207	              >
208	                <CardTitle>{t('Storage Area Network')}</CardTitle>
209	              </CardHeader>
210	              <CardBody>
211	                <Flex direction={{ default: 'row' }}>
212	                  <FlexItem>
213	                    <TextContent>
214	                      <Text component="small">
215	                        {t(
216	                          'Use groups of shared LUNs from local cluster nodes to create StorageClases with Fusion Data Foundation Access for SAN.'
217	                        )}
218	                      </Text>
219	                    </TextContent>
220	                  </FlexItem>
221	                  <FlexItem align={{ default: 'alignRight' }}>
222	                    <Radio
223	                      isDisabled={shouldDisableSAN}
224	                      isChecked={selectedOption === ExternalSystemOption.SAN}
225	                      onChange={() =>
226	                        setSelectedOption(ExternalSystemOption.SAN)
227	                      }
228	                      name="setup-scale-radio"
229	                      id="setup-scale-radio"
230	                    />
231	                  </FlexItem>
232	                </Flex>
233	              </CardBody>
234	            </Card>
235	          </FlexItem>
236	        </>
237	      )}
238	    </Flex>
239	  );
240	};
241	
242	const ModalHeader: React.FC = () => {
243	  const { t } = useCustomTranslation();
244	  return (
245	    <>
246	      <Title headingLevel="h1" id="welcome-df-modal-title">
247	        {t('Connect to external storage')}
248	      </Title>
249	      <TextContent>
250	        <Text component="small">
251	          {t(
252	            'Data Foundation simplifies persistent storage and data services across your cloud-native infrastructure'
253	          )}
254	        </Text>
255	      </TextContent>
256	    </>
257	  );
258	};
259	
260	export const ExternalSystemsSelectModal: ModalComponent = ({ closeModal }) => {
261	  const { t } = useCustomTranslation();
262	  const navigate = useNavigate();
263	  const [selectedOption, setSelectedOption] =
264	    React.useState<ExternalSystemOption>(null);
265	
266	  const handleNext = () => {
267	    if (selectedOption === ExternalSystemOption.RedHatCeph) {
268	      navigate('/odf/external-systems/ceph/~create');
269	    } else if (selectedOption === ExternalSystemOption.IBMFlash) {
270	      navigate('/odf/external-systems/flash/~create');
271	    } else if (selectedOption === ExternalSystemOption.Scale) {
272	      navigate('/odf/external-systems/scale/~create');
273	    } else if (selectedOption === ExternalSystemOption.SAN) {
274	      navigate('/odf/external-systems/san/~create');
275	    }
276	    closeModal();
277	  };
278	
279	  return (
280	    <Modal
281	      aria-label={t('Connect external system')}
282	      width="auto"
283	      isOpen={true}
284	      title={t('Connect external system')}
285	      header={<ModalHeader />}
286	      onClose={closeModal}
287	      actions={[
288	        <Button
289	          key="create-storage-cluster"
290	          variant={ButtonVariant.primary}
291	          onClick={handleNext}
292	          isDisabled={!selectedOption}
293	        >
294	          {t('Next')}
295	        </Button>,
296	        <Button
297	          key="create-storage-cluster"
298	          variant="link"
299	          onClick={closeModal}
300	        >
301	          {t('Cancel')}
302	        </Button>,
303	      ]}
304	    >
305	      <TextContent>
306	        <Text component="h4">
307	          {t('Select a platform to connect an external storage')}
308	        </Text>
309	        <Text component="small">
310	          {t(
311	            'This selection determines the storage capabilities of your cluster. Once configured it cannot be changed.'
312	          )}
313	        </Text>
314	      </TextContent>
315	      <ConfigureExternalSystems
316	        selectedOption={selectedOption}
317	        setSelectedOption={setSelectedOption}
318	      />
319	    </Modal>
320	  );
321	};

